/// <summary>
/// The <c>ETG_WithholdTaxReportContract</c> class is the data contract class for sales register report
/// report.
/// </summary>
[
    DataContractAttribute,
    SysOperationGroupAttribute('DateRange', "@SYS41297", '1')
    ]
    public class ETG_WithholdTaxReportContract implements SysOperationValidatable
{
    FromDate                fromDate;
    ToDate                  toDate;

}

Method.Source:
[
    DataMemberAttribute('FromDate'),
    SysOperationLabelAttribute(literalStr("@SYS5209")),
    SysOperationHelpTextAttribute(literalStr("@SYS5209")),
    SysOperationDisplayOrderAttribute('1'),
    SysOperationGroupMemberAttribute('DateRange')
]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[
    DataMemberAttribute('ToDate'),
    SysOperationLabelAttribute(literalStr("@SYS14656")),
    SysOperationHelpTextAttribute(literalStr("@SYS14656")),
    SysOperationDisplayOrderAttribute('2'),
    SysOperationGroupMemberAttribute('DateRange')
]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

public boolean validate()
{
    boolean isValid = true;
    if (!fromDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180311"));
    }
    if (!toDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180217"));
    }
    if (fromDate > toDate)
    {
        isValid = checkFailed("@SYS300457");
    }
    return isValid;
}
